var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>치명적인 정보 오염 감지.</color>","JPN":"<color=#ff3636>致命的な情報汚染を検知。</color>","ENG":"<color=#ff3636>Critical data corruption detected.</color>","TWN":"<color=#ff3636>感應到致命性的情報污染。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_06"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>잔여동력 0.3%. 사고회로 보호를 위해 재기동 절차가 필요합니다.</color>","JPN":"<color=#ff3636>残余エネルギー0.3％。思考回路の保護のため再起動手続きが必要です。</color>","ENG":"<color=#ff3636>Current remaining power is at 0.3%. Reinitialization is required to protect reasoning system.</color>","TWN":"<color=#ff3636>剩餘動能 0.3%。須重新啟動以保護思考迴路。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후우……. 져 버렸네.","JPN":"ふう……負けてしまったわ。","ENG":"Ugh… I lost.","TWN":"呼……我輸了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"음도 못 잡게 따라붙다니, 집요한 점은 상대적으로 덜 귀여운걸.","JPN":"音も出ないように追いつくなんて、執拗なところは相対的に可愛くないわね。","ENG":"You wouldn't even let me play a single note. I can't say I'm a big fan of such persistence.","TWN":"完全不讓我有喘息空間欸，你固執的可愛扣分！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"실컷 침식파에 시달리게 한 주제에 엄살 피우지 마십시오.","JPN":"散々侵食波で追い詰めてきたくせに大げさに言わないでください。","ENG":"You don't get to whine after bombarding me with that much C-Ray.","TWN":"這些侵蝕波都是你釋放的，請不要做賊喊抓賊。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 그래도 한 방 먹였다니 기쁘네.","JPN":"フフッ。でも一発は食らわせたみたいで嬉しいわ。","ENG":"Heh. I'm glad I got a few punches in, at least.","TWN":"呵呵～不過這一拳挨得真是痛快～"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"돌아가면 다른 동료들한테 자랑이라도 해야 하나. 비웃음만 사는 거 아닐지 몰라.","JPN":"帰ったら仲間たちに自慢でもしようかしら。嘲笑ばかりされたら困るけど。","ENG":"Should I brag about this to my colleagues when I get back? Maybe I'll just become a laughingstock.","TWN":"我回去要跟同事炫耀一下嗎？但他們應該只會笑我吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"신체 구조가 붕괴하고 있군요. 윌버는 어디 있습니까.","JPN":"身体構造が崩壊していますね。ウィルバーはどこにいますか。","ENG":"Your physical structure is imploding. Where is Wilbur?","TWN":"身體結構正在崩壞中呢。韋爾伯在哪裡？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"옥상에. 지금쯤 헬기가 도착했을 거야.","JPN":"屋上。今頃ヘリが到着したんじゃないかしら。","ENG":"On the rooftop. The helicopter should be just arriving.","TWN":"在屋頂，不過直升機應該已經到了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지금 가면 늦기 전에 아슬아슬하게 시간을 맞출 수 있어.","JPN":"今行けばギリギリ間に合うと思うわ。","ENG":"You can just make it before it's too late if you go there now.","TWN":"現在上去的話，或許還勉強趕得上。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"설득이 통해서 다행이군요. 질문에 대답해 주셔서 감사합니다.","JPN":"説得が通じて幸いですね。質問に答えていただきありがとうございます。","ENG":"I'm glad you can be reasoned with. Thank you for answering my question.","TWN":"幸好溝通有效，謝謝你的回答。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"호라이즌.","JPN":"ホライズン。","ENG":"Horizon.","TWN":"地平線。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"네가 지금 사용하고 있는 몸은 말이야, 아주아주 예전에 만들어진 거야.","JPN":"あなたが今使っている体はね、ずっと昔に作られたものよ。","ENG":"That body of yours right now… it was built a long, long time ago.","TWN":"你現在使用的身體，是非常非常久以前製造的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"우리 같은 그림자 따위가 범접하지 못할, <color=#ffd34c>왕</color>의 보물이지.","JPN":"私たちみたいなシャドウごときじゃ近づけない、<color=#ffd34c>王</color>の宝物。","ENG":"The treasure of <color=#ffd34c>kings</color> that lowly Shadows like us dare not covet.","TWN":"是像我們這種暗影都不敢冒犯的<color=#ffd34c>王</color>的寶物。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"전 안 물어 봤습니다.","JPN":"私は質問していません。","ENG":"I didn't ask.","TWN":"我沒問你這個問題。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그래. 물어 봤으면 나도 안 말해 줬어. 결국 어떻게 써야 하는지도 모른다는 뜻이니까.","JPN":"そうね。聞かれたなら私も言わなかったわ。それって、どう使えばいいのかもわからないという意味だからね。","ENG":"Right. I wouldn't have told you this if you had asked. That would mean you wouldn't even know how to use it properly.","TWN":"嗯，就算你問我也不會告訴你，因為我也不知道該如何使用它。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만……. 알고 있으면서 왜 쓰지 않은 거야?","JPN":"でも……わかっていながらどうして使わなかったの？","ENG":"So… How come you didn't use it properly, even when you know how?","TWN":"不過……你明明知道，為什麼不使用？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이번 건이 지극히 개인적인 문제이기 때문입니다.","JPN":"今回の件が極めて個人的な問題だからです。","ENG":"Because this case is a purely personal issue for me.","TWN":"因為這次的事件，是單純的個人恩怨。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"수치스러운 가정사가 얽혀 있어서 자세히는 설명해 드릴 수 없군요.","JPN":"恥ずべき家庭事情が絡んでいて詳しくは説明できませんね。","ENG":"I can't go into details as it involves a rather shameful family history.","TWN":"所謂家醜不可外揚，詳細內容恕我無可奉告。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗, 귀여운 소리만 골라서 한다니까.","JPN":"フフッ、もう可愛いんだから。","ENG":"Haha, you say the darndest things, don't you.","TWN":"呵呵～真是官腔～"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그러니까 다음에 다시 만날 때는……. 꼭 죽여 줄게.","JPN":"だから、次に会ったら……必ず殺してあげる。","ENG":"Well, next time we meet… I'll be sure to kill you.","TWN":"總之下次再見面之時……就是你的死期！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"즐거운 합주였어. 호라이즌.","JPN":"楽しい合奏だったわ、ホライズン。","ENG":"I enjoyed our little duet, Horizon.","TWN":"剛剛的合奏很棒，地平線。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……데몬 타입 침식체, 신체 붕괴를 확인했습니다.","JPN":"……デーモンタイプ侵食体、身体崩壊を確認しました。","ENG":"…Physical disintegration of Demon-Type C.O. confirmed.","TWN":"……惡魔型侵蝕體，身體崩潰確認。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"회전익 항공기 1체. 건물 상공으로 접근 중.","JPN":"回転翼航空機1機。建物の上空へ接近中。","ENG":"Single rotary wing aircraft… approaching the airspace above the building.","TWN":"1台旋翼機正接近建築物上方。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"새치기라니 용납할 수 없군요.","JPN":"割り込みを許すわけにはいきませんね。","ENG":"I will not tolerate any attempts to cut in line.","TWN":"竟然插隊，不可原諒。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HELI_TIDE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>블랙테일. 탑승 대기 중입니다.</color>","JPN":"<color=#ffd34c>ブラックテール。搭乗待機中です。</color>","ENG":"<color=#ffd34c>Black Tail, standing by for exfil.</color>","TWN":"<color=#ffd34c>黑尾，等候搭乘中。</color>"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HELI_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L38_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"좋아! 제때 도착했군!","JPN":"よし！　間に合ったな！","ENG":"Great! Right on time!","TWN":"很好！非常準時！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"고맙다, 셰나. 네 덕분에 위기를 모면하는 날이 올 줄이야.","JPN":"助かったぞ、シェナ。お前のおかげで危機は免れた。","ENG":"Thank you, Shena. Who knew you'd actually save my skin one day?","TWN":"謝啦，世娜。沒想到我會有因為你而得救的一天。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자, 자기야……. 하늘 좀 봐. 저거 전부 차원함선 맞지?","JPN":"ダ、ダーリン……空を見て。あれは全部次元艦船だよね？","ENG":"B-babe… Look at the sky. Are they all dimensional ships?","TWN":"親…親愛的…你看天上，那些全都是次元艦船吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래. 자기야. 전부 저 괴물 같은 사채꾼을 처리하러 몰려온 게 틀림없어.","JPN":"ああ、ハニー。全部あの化け物みたいな闇金野郎を始末するために集まったに違いない。","ENG":"That's right, babe. They must be here to get rid of that monstrous loan shark.","TWN":"沒錯！他們肯定都是要來處理那個怪物高利貸的！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"후, 후후……. 결국 예전이랑 하나도 안 달라졌단 뜻이지.","JPN":"ふふふふ……結局、以前と全く変わっていないということだ。","ENG":"Hah, hah hah... In the end, nothing's changed.","TWN":"呵，呵呵呵……結果和以前一樣。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"나는 살아남는다! 살아 있기만 하면 기회는 얼마든지 다시 잡을 수 있어!","JPN":"僕は生き残る！　生きていればまたチャンスはいくらでもある！","ENG":"I will survive! There's always a second chance as long as I survive!","TWN":"存活下來的是我！只要活著就有機會！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HELI_TIDE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>비상. 메인 로터 파괴. 비행이 불가합니다.</color>","JPN":"<color=#ffd34c>緊急事態。メインローター破壊。飛行ができません。</color>","ENG":"<color=#ffd34c>ALERT. Main rotor destroyed. Aircraft grounded.</color>","TWN":"<color=#ffd34c>緊急狀態，主要旋翼遭到破壞，無法飛行。</color>"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HELI_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L1_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"뭐…… 뭐야! 저격인가! 어디서?!","JPN":"な、なんだ！　狙撃か！　どこから！？","ENG":"W-what the?! Is it a sniper?! But where?","TWN":"什……什麼！！是狙擊嗎？從哪來的？！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기야, 헬기 위에 꽂혀 있는 저거…… 쇠파이프 아냐?","JPN":"ダーリン、ヘリの上に刺さっているあれ……鉄パイプじゃない？","ENG":"Babe… is that a metal pipe stuck on top of the helicopter?","TWN":"親愛的，直升機上好像插著什麼東西……那是鐵管嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"쇠파이프……? 설마!","JPN":"鉄パイプ……？　まさか！","ENG":"A metal pipe…? It can't be…!","TWN":"鐵管……？難道是！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"손님이 방문하면 얼굴을 보이고 대응하는 것이 상식 아닙니까.","JPN":"お客様が訪問したなら、顔を出して対応するのが常識ではないでしょうか。","ENG":"Isn't it common sense to greet your guest in person?","TWN":"有客人造訪時，出來迎接不是基本禮貌嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"비즈니스의 기본 자세부터 글러먹었군요, 윌버.","JPN":"ビジネスの基本が全くできていませんね、ウィルバー。","ENG":"You don't even have basic business etiquette down, Wilbur.","TWN":"你連經營事業的基本原則都不知道嗎，韋爾伯。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"호, 호라이즌……!!","JPN":"ホ、ホライズン……！！","ENG":"H-Horizon…!!","TWN":"地…地平線……！！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"셰나는……. 당한 건가?","JPN":"シェナは……やられたのか？","ENG":"Did Shena… lose, then?","TWN":"世娜……也輸了嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"빌어먹을! 결국 잘난 척만 실컷 하더니 아무것도 못했잖아!","JPN":"くそ！　あの女、偉そうなくせに結局役に立たなかったのか！","ENG":"Damn it! Turns out she's just as useless as the rest of them!","TWN":"可惡！還裝作一副很厲害的樣子！結果只是一張嘴很厲害！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"성품과 별개로 당신보다는 유능하다고 판단됩니다만.","JPN":"品性とは別に、彼女はあなたよりは有能だと判断されますが。","ENG":"I beg to differ. For all her faults in personality, she's much more capable than you'll ever be.","TWN":"撇開人品不談，她確實是比你厲害沒錯。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"닥쳐! 닥쳐! 제발 좀 그 빌어먹을 주둥이 좀 닥쳐어어어!!","JPN":"黙れ！　黙れ！　黙れ！　毎回毎回ナメた口利きやがって！！","ENG":"Shut up! Shut up! Can't you shut that mouth of yours for once?!!","TWN":"住嘴！住嘴！我拜託你那張可惡的嘴不要說話！！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"왜 날 이렇게 괴롭히는 거냐! 내가 뭘 그렇게 잘못했다고!","JPN":"なぜここまでして僕を苦しめるんだ！　僕の何がそんなにいけなかったんだよ！","ENG":"Why do you keep harassing me?! What have I ever done to you?!","TWN":"你為何一直要找我麻煩！我到底是犯了什麼滔天大罪！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래, 검찰에 가서 자수라도 할까? 탐사 도중에 사실은 사람을 버렸습니다, 하고?","JPN":"そうだな、警察に行って自首でもしようか？　探査の途中、実は人を見捨ててしまいましたって？","ENG":"Fine, should I go turn myself in? Should I tell them, \\"I actually left someone behind in the Counterside\\"?","TWN":"還是要我去警察局自首？說我在探索過程中犯下遺棄罪？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그렇게 하면 속이 시원해지겠냐! 어?! 어렵게 성공한 남의 인생 말아먹어야 속이 시원해지겠냐고!","JPN":"そうすれば気持ちが晴れるのか？　ああ？　苦労して成功した人間の人生を台無しにして、貴様はスカッとするのかよ！","ENG":"Would that make you feel better?! Huh?! Will bringing my successful life to ruin finally make you feel better?!","TWN":"這樣你會比較開心嗎？是嗎？！要毀掉成功人士的人生你才會開心嗎？！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"말귀 못 알아듣는 것도 재능이군요. 윌버. 편의주의적인 사고 방식으로 평생을 살았으니 이해해 드리겠습니다.","JPN":"話が通じないのもひとつの才能ですね、ウィルバー。あなたは便宜主義的な考え方でずっと生きていたと思いますので理解はしてあげますが。","ENG":"You have a knack for misinterpreting what others say, Wilbur. Then again, I understand given how that's you've lived your entire life.","TWN":"老是誤解別人的話也是種才能呢，韋爾伯。因為你的人生一直都是投機主義，是可以理解。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 원하는 건 당신이 대출금과 이자를 상환하는 것입니다.","JPN":"私が求めるのは、あなたが貸出金と利子を返済することです。","ENG":"All I want is that you repay the principal and interest of the debt you owe me.","TWN":"我希望的是你償還本金和利息。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"개수작 부리지 마! 7억 크레딧이 말만 하면 어디 하늘에서 뚝 떨어지는 액수인 줄 알아?!","JPN":"いい加減にしろ！　7億クレジットを出せと言われたらパッと出せる金額だと思ってんのか！？","ENG":"Don't make me laugh! You think 700 million credits will just fall out of the sky?!","TWN":"少胡說八道！你以為7億是隨隨便便就拿得出來的金額嗎？！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"돈은 휴먼들이 만든 가장 오래된 약속입니다.","JPN":"お金はヒューマンが作った最も古い約束です。","ENG":"Money is the oldest token of promise that humans have invented.","TWN":"金錢是人類創造的歷史最悠久的約定。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그리고 저는 약속을 어기는 행동을 싫어합니다. 윌버.","JPN":"そして私は約束を破る行動が嫌いです、ウィルバー。","ENG":"And I hate it when people break their promise, Wilbur.","TWN":"而我討厭不履行約定的行為，韋爾伯。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"갚지 않겠다면…….","JPN":"返さないなら……","ENG":"If you will not pay me back…","TWN":"不還的話……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"가까이 오지 마! 그 이상 한 발짝도 가까이 오지 마!!","JPN":"近寄るな！　それ以上僕に一歩も近づくな！！","ENG":"Get away from me! Don't you dare take one more step!!","TWN":"別過來！不准你再靠近一步！！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"히, 히힉……! 그렇게 나온다는 거지? 그럼 나도 다 생각이 있단 말이다!","JPN":"ヒ、ヒヒッ……！　そう来るんだな！　僕にも対策はあるんだぞ！","ENG":"Eep… Heh… Haha! So is that the way you're going to be? Then I've got a plan myself!","TWN":"呼呼……！你要這樣逼我是吧？！那我也有我的對策！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그 카메라, 유적에서 입수한 아티팩트로군요.","JPN":"そのカメラ、遺跡で入手したアーティファクトですね。","ENG":"That camera must be the artifact you acquired from the ruins.","TWN":"那個相機，是在遺跡取得的人造神器嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래, 셰나가 넘겨 준 기술을 사용해서 한계까지 증폭시켜 뒀지……!","JPN":"ああ、シェナが渡した技術を使って限界まで増幅させておいたんだよ！！","ENG":"That's right. And with Shena's technology, I've amplified its power to its limits!","TWN":"沒錯，我利用世娜傳給我的技術，將它增幅至最大極限……！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"지금 이걸로 찍으면 무슨 일이 벌어지는 줄 알아? 응?","JPN":"これで撮ったら何が起こるかわかるか？　あん？","ENG":"Can you guess what would happen if I took a picture with it right now? Hm?","TWN":"現在只要我按下快門，你知道會發生什麼事嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"단념하시죠. 윌버. 그건 당신이 책임질 수 있는 범주 바깥의 일입니다.","JPN":"断念してください、ウィルバー。それはあなたが責任を負える範囲を超えたものです。","ENG":"Don't bother, Wilbur. That is something beyond the scope of what you can handle.","TWN":"勸你打消這個念頭，韋爾伯。這已經超出你能負責的範圍。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"다 뒈지는 거야! 샤레이드고 뭐고, 전부 쑥대밭이 되는 거라고!","JPN":"みんなくたばるんだよ！　シャレードも何もかも、すべてが廃墟になるんだ！","ENG":"We're all going to die! Everything around here will be gone! It'll wipe Charade off the map!","TWN":"全都去死吧！管他查雷德還什麼的！全都夷為平地吧！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그러니 이제 날 작작 괴롭혀……!","JPN":"だからもう僕を苦しめるのはいい加減……！","ENG":"So stop harassing me already…!","TWN":"你要是再刺激我的話……！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"윌버. 채무를 이행하십시오.","JPN":"ウィルバー、債務を履行してください。","ENG":"Wilbur. Repay your debt.","TWN":"韋爾伯，請償還債務。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"작작하라고오오오오!!","JPN":"いい加減にしろおおおぉぉぉーっ！！","ENG":"Enough already!!","TWN":"不要再刺激我！！！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>도시관리국에서 안내드립니다.</color>","JPN":"<color=#ff3636>都市管理局からお知らせします。</color>","ENG":"<color=#ff3636>This is an announcement from City Management.</color>","TWN":"<color=#ff3636>城市管理局通知。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>현재, 제프티 바이오테크 본사의 CSE 레벨이 4로 상승. 국지적 현실 붕괴 현상 발생.</color>","JPN":"<color=#ff3636>現在、ジェフティ・バイオテック本社のCSEレベルが4に上昇。局地的に現実崩壊現象が発生。</color>","ENG":"<color=#ff3636>CSE Level around Jehuty Biotech has been elevated to level 4. A local reality collapse has occurred.</color>","TWN":"<color=#ff3636>現在傑夫堤生物科技總公司的CSE等級上升至4。發生局部崩壞現象。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>적색 긴급 방어령 발령. 전 태스크포스는 4종 대형 침식체의 요격을 준비해 주시기 바랍니다.</color>","JPN":"<color=#ff3636>パターンレッドの緊急防御令発令。全タスクフォースカンパニーは、第4種大型侵食体の迎撃に備えてください。</color>","ENG":"<color=#ff3636>Red alert issued. All TASKFORCEs are to prepare interception of Category 4 C.O.</color>","TWN":"<color=#ff3636>發布紅色緊急防衛令。所有特遣勢力請預備狙擊4類大型侵蝕體。</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"아, 아아……. 아아아아…….","JPN":"あ、あ……あああ……","ENG":"Ah, aah… Aaaah…","TWN":"啊啊……啊啊啊……"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>타입 브리트라 제프티 바이오테크 본사 상공에서 관측!</color>","JPN":"<color=#ffd34c>タイプブリトラ、ジェフティ・バイオテック本社上空で観測！</color>","ENG":"<color=#ffd34c>Type Britra spotted in the airspace above Jehuty Biotech!</color>","TWN":"<color=#ffd34c>類型 佈雷特，傑夫堤生物科技總公司上空觀測中！</color>"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L42_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>크, 큰일입니다! 단일 개체가 아닙니다! 새로운 반응이……!</color>","JPN":"<color=#ffd34c>た、大変です！　単一個体ではありません！　新しい反応が……！</color>","ENG":"<color=#ffd34c>T-this can't be good! There's more than one of them! I'm reading more signatures…</color>","TWN":"<color=#ffd34c>大…大事不好！不是單一個體！新的反應……！</color>"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>4체, 아니 8, 9! 계속해서 늘어나고 있습니다!!</color>","JPN":"<color=#ffd34c>4体、いや、8、9！　増え続けています！！</color>","ENG":"<color=#ffd34c>Four… no, eight! Nine! They just keep coming!</color>","TWN":"<color=#ffd34c>4台…不，8、9！持續增加中！！</color>"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L44_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>사람들 대피시켜! 관리국에 넘버링 태스크포스 급파를 요청해라! 어서!</color>","JPN":"<color=#ffd34c>市民を避難させろ！　管理局にナンバリングタスクフォースの急派を要請せよ！　急げ！</color>","ENG":"<color=#ffd34c>Evacuate everyone! Request the Administration immediately deploy numbered TASKFORCEs! Now!</color>","TWN":"<color=#ffd34c>疏散人群！請管理局緊急派出特遣勢力！快！</color>"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L45_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하하하하하하하하하!! 뭐야, 역시 난 하면 되는 놈이잖아!!","JPN":"ハハハハハハハ！！　なんだ、やっぱり僕はやればできるやつじゃないか！！","ENG":"Hahahaha! Looks like I've still got some clout after all!","TWN":"哇哈哈哈哈哈！！什麼嘛～沒有什麼我辦不到的事嘛！！"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"보이냐, 호라이즌!! 내가, 내가 저들을 부른 거다!","JPN":"ほら、見えるか、ホライズン！　僕が、この僕が彼らを呼び出したんだ！！","ENG":"See that, Horizon?! I'm the one who summoned those things!","TWN":"地平線，看到沒！是我把他們找來的！"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"멸망한 미래에서 저들을 불러낸 거야!!","JPN":"滅亡した未来から彼らを呼び出したんだよ！！","ENG":"I've called them from an apocalyptic future!!","TWN":"我從滅亡的未來中呼喚他們來的！"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"내가 실패한다고?! 너한테 또 가진 돈을 죄다 바치고 거렁뱅이 신세로 전락하라고?!","JPN":"僕が失敗するだと！？　貴様に全ての財産を渡して、乞食に転落しろだと！？","ENG":"Did you really think I'll fail?! You expect me to pay you all my money and be broke again?!","TWN":"我會輸？！要我又把所有錢都給你，淪落成窮鬼？！"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"절대 안 돼!! 두 번 다시 그런 꼴은 용납 못 해!!","JPN":"ご免だね！！　二度とあんな目には遭いたくないんだ！！","ENG":"Never!! I'll never go back to being a loser like that!!","TWN":"絕對不可能！！我不可能再回到那個樣子！！"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"내 두뇌를 몰라 주던 멍청한 놈들!! 너 같은 괴물을 내버려 둔 무식한 놈들!!","JPN":"僕の賢さを理解してくれなかったバカな連中も！！　貴様みたいな化け物をほったらかした無知な連中も！！","ENG":"Damn those fools who didn't recognize my genius!! Damn them for leaving a monster like you to roam free!!","TWN":"低估我的腦袋的愚蠢傢伙們！！放過你這種怪物的無知傢伙！！"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"전부 죽여 버리겠어!! 죄다 죽여 버리겠어!! 나 혼자 뒈질 바엔 다 같이 죽여 버리겠어!!","JPN":"全部殺してやる！！　皆殺しにしてやる！！　僕だけがやられるなら、全員まとめて殺してやる！！","ENG":"I'll kill them!! I'll kill them all!! I might as well as take them all down with me!!","TWN":"我要把你們全殺掉！！殺光光！！我要跟你們同歸於盡！！"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>잔여 동력 0.15퍼센트. 침식파 방호 불가. 재기동이 필요합니다.</color>","JPN":"<color=#ff3636>残余エネルギー0.15％。侵食波防護不可。再起動が必要です。</color>","ENG":"<color=#ff3636>0.15% power remaining. Corruption Ray protection compromised. Reinitialization required.</color>","TWN":"<color=#ff3636>剩餘動能0.15%。無法抵擋侵蝕波，需要重新啟動。</color>"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_06"},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"왜, 어디 더 와 보시지 그래?! 응?! 호라이즈으으으은!!","JPN":"ほら、かかってこいよ！　なあ！　ホライズウウゥゥン！！","ENG":"Well, what's keeping you?! Huh?! Horizooon!!","TWN":"怎麼樣？敢再靠近我一步試試看！嗯？！地平線！！！！！"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"무섭겠지! 무서워서 말이 안 나오겠지!!","JPN":"怖いだろ！　怖くて言葉も出ないよなあ！！","ENG":"You must be terrified! So terrified that you're at a loss for words!","TWN":"很害怕吧！怕到說不出話來對吧！！"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇게까지 같은 휴먼들을 짓밟으면서 살고 싶습니까?","JPN":"そうやって他のヒューマンを踏みにじってまで、生き残りたいのですか。","ENG":"Do you really wish to trample on your fellow humans so badly?","TWN":"你就算踩著同樣是人類的屍體也想活下去嗎？"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 휴먼들을 싫어합니다. 윌버.","JPN":"私はヒューマンが嫌いです、ウィルバー。","ENG":"I despise humans, Wilbur.","TWN":"我討厭人類，韋爾伯。"},"stage":{"bg":"DATABASE","bgm":"THEMA_EXCUTE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그래서 그들을 끝까지 싫어하고 싶었습니다.","JPN":"だから最後まで、彼らを嫌いなままでいたかったです。","ENG":"And I wished to remain that way.","TWN":"原本我想討厭他們到底。"},"stage":{"bg":"DATABASE","bgm":"THEMA_EXCUTE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 휴먼들은, 끈질기게 그러지 않아도 된다고 주장합니다.","JPN":"しかしヒューマンたちは、しつこくそうしなくてもいいと主張してきます。","ENG":"But some humans tenaciously insist that it does not have to be that way.","TWN":"但人類卻表示不需要那麼執著。"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_EXCUTE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"누구보다 비참하게 살아 왔는데도 희망을 잃지 않고.","JPN":"誰よりも惨めに生きてきたのに、希望を失わずに。","ENG":"Despite their miserable lives, they cling onto hope.","TWN":"雖然一直過著比任何人都悲慘的生活，卻不失去希望。"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_EXCUTE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"자신이 원치 않게 저지른 잘못 탓에 평생 후회하고.","JPN":"やむを得なかった過ちのせいで、一生を後悔して。","ENG":"They regret all their lives for the mistakes they've made.","TWN":"因為迫於無奈的錯誤而悔恨一生。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_EXCUTE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이기적으로 살 수 있을 텐데도 다른 휴먼을 감싸고.","JPN":"利己的に生きられるはずなのに、他のヒューマンを助けようとして。","ENG":"They selflessly look after other humans when they have every right to be selfish.","TWN":"明明可以自私地活著，卻照顧的其他人類。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_EXCUTE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"불공평한 세상이지만 법 앞에서 누구나 평등하게 심판하려 하고.","JPN":"不公平な世の中でも、法のもとで誰しも平等に裁こうとして。","ENG":"They believe everyone is equal before the law even in this unjust world.","TWN":"雖然身處不公平的世界，卻希望在法律面前人人平等。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_EXCUTE","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……강한 힘을 가졌더라도, 그 힘을 약자들을 지키기 위해 사용합니다.","JPN":"……強い力を持っていても、その力を弱者を守るために使います。","ENG":"…And their power to protect the weak.","TWN":"……雖然很有能力，卻願意用那股力量來保護弱者。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_EXCUTE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"무슨 개소리를 지껄이려나 했더니…….","JPN":"何をほざくのかと思ったら……","ENG":"I was wondering what you were babbling about…","TWN":"你在說什麼鬼話……"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그게 당연한 거다! 약한 놈들이나 서로 핥아 주면서 자기들은 버러지가 아니라고 세뇌하는 거지!","JPN":"そんなの当たり前だ！　弱いんだからお互い傷を舐め合って、自分たちは虫けらじゃないと洗脳するだけなんだよ！","ENG":"Of course they're like that! Those weaklings have to brainwash themselves into thinking they're not scumbags by taking care of each other!","TWN":"那是什麼廢話！那只是弱者間自我安慰自己不是失敗者吧！"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇습니다. 휴먼.","JPN":"そうですね、ヒューマン。","ENG":"That's right, human.","TWN":"沒錯，人類。"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신들은, 서로 지켜 줘야 합니다. 너무 약해 빠졌으니까요.","JPN":"あなたたちは、お互いを守るべきです。弱すぎますから。","ENG":"Your kind must protect each other. Because you are all too weak.","TWN":"你們必須彼此扶持，因為太脆弱。"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>잔여 동력 0.06%. 재기동이 필요합니다.</color>","JPN":"<color=#ff3636>残余エネルギー0.06％。再起動が必要です。</color>","ENG":"<color=#ff3636>Current remaining power is at 0.06%. Reinitialization required.</color>","TWN":"<color=#ff3636>剩餘動能0.06%。需要重新啟動。</color>"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>강제 재기동 절차를 시행합니다. 예상 소요 시간 ███,███시간.</color>","JPN":"<color=#ff3636>強制再起動手続きを行います。予想所要時間 ███、███時間。</color>","ENG":"<color=#ff3636>Force reinitializing… Estimated time: ███,███ hours.</color>","TWN":"<color=#ff3636>執行強制重新啟動程序。預計需要 ███,███小時。</color>"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 현 시간부로 사적인 수금 활동을 일시 중단하겠습니다.","JPN":"現時間をもって、私は私的な集金活動を一時中断します。","ENG":"As of now, I will suspend all personal collection activities.","TWN":"現在起，我會暫時停止私人討債行動。"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그리고 약해 빠진 휴먼들을 지키고자 모든 것을 바친 자를 위해…….","JPN":"そして、弱いヒューマンたちを守ろうと、すべてを捧げた者のために……","ENG":"And for the sake of someone who sacrificed her everything to protect these weak humans…","TWN":"並且，為了那些獻上所有要守護脆弱人類的人……"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"재기동하겠습니다.","JPN":"再起動します。","ENG":"I will reinitialize.","TWN":"我會再重新啟動。"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하하하하하! 재기동을 해? 겁나서 도망친다고 그러지! 자기 손으로 죽기 편해서 참 좋겠어!!","JPN":"ハハハハ！　再起動だと？　怖いから逃げるって言っていいんだぞ？　自ら死を選べるなんて羨ましいじゃないか！！","ENG":"Hahahaha! Reinitialize? Why don't you just admit you want to run away because you're scared? It must be so convenient checking out whenever you want!","TWN":"哈哈哈哈！重新啟動？明明就是因為害怕！可以自我了結還真方便！！"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>커넥터 강제 분리. 의사 모듈 직결 탑재 완료.</color>","JPN":"<color=#ff3636>コネクター強制分離。意思モジュール直結搭載完了。</color>","ENG":"<color=#ff3636>Force removing connector. Direct installation of self-will module completed.</color>","TWN":"<color=#ff3636>強制分離連接器。意識模組直接搭載完畢。</color>"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_02"},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>교전 형태로의 기동 목적을 입력하십시오.</color>","JPN":"<color=#ff3636>交戦モードでの起動目的を入力してください。</color>","ENG":"<color=#ff3636>State the purpose of activating combat mode.</color>","TWN":"<color=#ff3636>請輸入交戰型態的啟動目的。</color>"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"기동 목적은…….","JPN":"起動目的は……","ENG":"The purpose of activation is…","TWN":"啟動目的是……"},"stage":{"bg":"HORIZON_04","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"잊지 마, 호라이즌.","JPN":"忘れるな……ホライズン。","ENG":"Don't forget, Horizon.","TWN":"記住，地平線，"},"stage":{"bg":"BLACK","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"우리가, 내가 너를 만든 건…….","JPN":"私たちが、私があなたを作ったのは……","ENG":"We… I made you because…","TWN":"是我們…是我創造你的……"},"stage":{"bg":"BLACK","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……<color=#ffd34c>인류수호</color>.","JPN":"……<color=#ffd34c>人類の守護</color>。","ENG":"…<color=#ffd34c>Protect Mankind</color>.","TWN":"目的是……<color=#ffd34c>守護人類</color>。"},"stage":{"bg":"HORIZON_07","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"다, 당신, 아니, 너……. 설마 사채꾼…… 이라고?","JPN":"あ、あなたは、いや、貴様は……闇金野郎……か？","ENG":"Y-you… You're the loan shark?","TWN":"您…不對，你……是那個放高利貸……的？"},"stage":{"bg":"HORIZON_03","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_RUNNING"},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇습니다. 접니다.","JPN":"はい、私です。","ENG":"That's right. It's me.","TWN":"是的，就是我。"},"stage":{"bg":"HORIZON_03","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>모듈 탑재 방식 변경에 따른 기동시간 재계산. 예상 소요 시간 0.3초.</color>","JPN":"<color=#ff3636>モジュール搭載方式変更に伴う起動時間再計算。予想所要時間0.3秒。</color>","ENG":"<color=#ff3636>Recomputing activation time based on new module. Estimated time: 0.3 seconds.</color>","TWN":"<color=#ff3636>因模組搭載方式變更，故重新計算啟動時間。預計花費0.3秒。</color>"},"stage":{"bg":"HORIZON_03","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_06"},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>정보오염 방재 대응. 종료.</color>","JPN":"<color=#ff3636>情報汚染防衛対応、終了。</color>","ENG":"<color=#ff3636>Data corruption response… completed.</color>","TWN":"<color=#ff3636>預防情報污染作業完成。</color>"},"stage":{"bg":"HORIZON_03","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……결국 엠버 소장이 틀리지 않았군요.","JPN":"……結局アンバー所長は間違っていなかったようです。","ENG":"…So Director Ember was right all along.","TWN":"……結果琥珀所長是對的。"},"stage":{"bg":"HORIZON_03","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"합법적으로 늘어지게 잘 기회를 자진해서 걷어차 버렸습니다.","JPN":"合法的にダラダラ寝る機会を、自ら蹴ってしまいましたね。","ENG":"I've voluntarily discarded my chance to slumber without interruption.","TWN":"到手的機會卻主動放棄。"},"stage":{"bg":"HORIZON_03","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>범인류 이민선단 호위용 공간 도약 전투체. 시무르그 활성화.</color>","JPN":"<color=#ffd34c>汎人類移民船団護衛用、空間跳躍戦闘体。シムルグ活性化。</color>","ENG":"<color=#ffd34c>Space-jumping Escort Fighter for Exodus Fleet of Humankind… Simurgh activated.</color>","TWN":"<color=#ffd34c>凡人類移民船隊護衛型空間跳躍戰鬥體。西摩格啟動。</color>"},"stage":{"bg":"HORIZON_03","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>아베스타 드라이브 기동. CRF 소모를 중단하고 침식파 정제를 개시합니다.</color>","JPN":"<color=#ffd34c>アヴェスター・ドライブ起動。CRF消費を中断し、侵食波精製を開始します。</color>","ENG":"<color=#ffd34c>Avesta Drive activated. Suspending CRF usage. Initiating Corruption Ray refinement.</color>","TWN":"<color=#ffd34c>阿貝斯塔啟動。停止消耗CRF並開始製造侵蝕波。</color>"},"stage":{"bg":"HORIZON_03","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>교전 가능 시간 2초. 초과시 인공지능의 융해가 발생할 수 있습니다.</color>","JPN":"<color=#ffd34c>交戦可能時間2秒。超過時に人工知能の融解が発生する可能性が高いです。</color>","ENG":"<color=#ffd34c>Maximum engagement time: 2 seconds. Exceeding the maximum time may result in disintegration of the A.I.</color>","TWN":"<color=#ffd34c>可交戰時間為2秒。超過時可能導致人工智慧溶解。</color>"},"stage":{"bg":"HORIZON_03","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"2초. 접수했습니다.","JPN":"2秒、受け付けました。","ENG":"Two seconds. Acknowledged.","TWN":"2秒，收到。"},"stage":{"bg":"HORIZON_03","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"충분하고도 남겠군요.","JPN":"十分すぎて余りそうですね。","ENG":"That should be more than enough.","TWN":"綽綽有餘。"},"stage":{"bg":"HORIZON_03","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};